
.card {
  position: relative;
  width: 100%;
  max-width: 720px;
  margin: 0 auto;
  border: 1px solid var(--c-panel-border);
  border-radius: 18px;
  background: var(--surface-linen);
  box-shadow:
    0 18px 34px var(--c-fabric-shadow),
    inset 0 1px 0 var(--c-panel-glow),
    inset 0 -1px 0 rgba(122, 92, 69, 0.14);
  color: var(--c-charcoal);
  overflow: hidden;
}

.card::before {
  content: '';
  position: absolute;
  inset: 8px;
  border: 1px dashed var(--c-stitch);
  border-radius: 12px;
  opacity: 0.75;
  pointer-events: none;
}

.summary-strip {
  position: relative;
  list-style: none;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 15px 18px;
  cursor: pointer;
  user-select: none;
  background:
    radial-gradient(circle at top left, rgba(255, 255, 255, 0.45), transparent 42%),
    linear-gradient(135deg, rgba(255, 248, 239, 0.92), rgba(225, 208, 183, 0.9)),
    var(--surface-canvas);
  transition:
    background-position 0.22s ease,
    box-shadow 0.22s ease,
    filter 0.22s ease;
}

.summary-strip::-webkit-details-marker {
  display: none;
}

.summary-strip::after {
  content: '';
  position: absolute;
  left: 18px;
  right: 18px;
  bottom: 8px;
  border-bottom: 1px dashed rgba(148, 112, 82, 0.45);
  pointer-events: none;
}

.card[open] > .summary-strip {
  box-shadow:
    inset 0 -1px 0 rgba(184, 137, 83, 0.5),
    inset 0 1px 0 rgba(255, 255, 255, 0.4);
}

.summary-strip:hover {
  background-position: 8px 0, 0 0, 0 0;
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.55),
    0 10px 20px rgba(105, 78, 57, 0.08);
  filter: brightness(1.02);
}

.summary-main {
  display: flex;
  align-items: center;
  gap: 12px;
  min-width: 0;
}

.summary-icon {
  display: grid;
  place-items: center;
  width: 42px;
  height: 42px;
  border-radius: 14px;
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.28), rgba(255, 255, 255, 0)),
    var(--surface-denim);
  color: #fffdf7;
  font-size: 1.02rem;
  flex-shrink: 0;
  border: 1px solid rgba(255, 255, 255, 0.24);
  box-shadow:
    0 10px 20px rgba(66, 84, 58, 0.22),
    inset 0 1px 0 rgba(255, 255, 255, 0.25);
}

.summary-copy {
  display: flex;
  flex-direction: column;
  gap: 2px;
  min-width: 0;
}

.summary-label {
  font-family: var(--font-serif);
  font-size: 0.98rem;
  font-weight: 700;
  color: var(--c-mahogany);
  letter-spacing: 0.4px;
}

.summary-hint {
  color: var(--c-ink-soft);
  font-size: 0.77rem;
}

.summary-meta {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-shrink: 0;
}

.rank-badge {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 5px 7px 5px 11px;
  border-radius: 999px;
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.55), rgba(255, 255, 255, 0.16)),
    var(--surface-canvas);
  border: 1px solid rgba(184, 137, 83, 0.45);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.78),
    0 4px 10px rgba(89, 64, 45, 0.08);
}

.rank-tag {
  font-size: 0.72rem;
  color: var(--c-ink-soft);
  font-weight: 700;
  letter-spacing: 0.08em;
}

.rank-value {
  display: inline-flex;
  align-items: center;
  min-height: 24px;
  padding: 0 10px;
  border-radius: 999px;
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.22), rgba(255, 255, 255, 0)),
    linear-gradient(135deg, #b97b5e, #8d5f49);
  color: #fff8ec;
  font-family: var(--font-serif);
  font-size: 0.78rem;
  font-weight: 700;
  letter-spacing: 0.6px;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.24);
}

.chevron {
  color: var(--c-mahogany);
  font-size: 0.9rem;
  transition: transform 0.28s ease;
}

.card[open] .chevron {
  transform: rotate(180deg);
}

.content-shell {
  overflow: hidden;
  height: 0;
  transition:
    height 0.24s ease,
    opacity 0.24s ease;
  opacity: 0;
}

.card[data-expanded='true'] .content-shell {
  opacity: 1;
}

.content-area {
  min-height: 0;
  overflow: hidden;
  padding: 0 18px;
}

.content-panel {
  padding: 14px 0 18px;
}

.empty-hint {
  padding: 14px 0 6px;
  color: var(--c-ink-soft);
  font-size: 0.82rem;
  font-style: italic;
}

.fade-enter-active,
.fade-leave-active {
  transition: opacity 0.22s ease, transform 0.22s ease;
}

.fade-enter-from,
.fade-leave-to {
  opacity: 0;
  transform: translateY(6px);
}

@media (max-width: 560px) {
  .summary-strip {
    align-items: flex-start;
  }

  .summary-meta {
    flex-direction: column;
    align-items: flex-end;
    gap: 6px;
  }

  .rank-badge {
    max-width: 170px;
  }

  .rank-value {
    max-width: 100%;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }
}
